//
//legend-minmaxlabels.js
import { MinmaxLabelParser } from './minmax-label/legend-minmax-label-parser';
import { getRawRanges } from '../axis/colorscale-helpers';
import { renderDom } from '../mark/dom-render';
import { getLegendAlignment } from './legend-utils';
// import { legend_helpers } from './legend-helper';
import { legend_helpers } from '../core/main-zc-init';
import { getFormattedValue } from '../formatter/formatter';

var ZC_legend_minmaxLabels = function(element, dimension, axisOptions, chartObj, orient, config) {
    var systemConf = chartObj.systemConf,
        minmaxlabelsOptions = axisOptions.minmaxlabels,
        legendOptions = config,
        colorbandOptions = legendOptions.colorBand,
        legendAlign = getLegendAlignment(legendOptions),
        sliderSize = legendOptions.filter.enabled ? getSliderSize(legendOptions.filter.slider, dimension, orient, legendAlign) : [0, 0],
        isDiscrete = colorbandOptions.ranges && colorbandOptions.ranges.length,
        reversed = legend_helpers.isReversedColorAxis(config),
        data = [],
        //Formatter
        columnInfo = chartObj.dataset.getColumn('clr'),
        datatype = columnInfo.datatype,
        formatConf = columnInfo[datatype];

    if (minmaxlabelsOptions.show) {
        if (isDiscrete) {
            var ranges = getRawRanges(config, chartObj);
            data = [ranges[0][0], ranges[ranges.length - 1][ranges[ranges.length - 1].length - 1]];
        } else {
            var scale_domain = chartObj.axes.clr.scale.domain();
            data = [scale_domain[0], scale_domain[scale_domain.length - 1]];
        }
    }

    if (reversed) {
        data.reverse();
    }

    let minmaxLabelsSpec = {
        format: d => getFormattedValue(formatConf, d, datatype, chartObj, 'minmaxlabels'),
        data,
        orient,
        dimension,
        sliderSize,
        config: minmaxlabelsOptions,
        globalFont: systemConf.canvas
    };

    let minmaxLabelMark = MinmaxLabelParser(minmaxLabelsSpec);
    renderDom(minmaxLabelMark, element);
};

function getSliderSize(sliderOptions, dimension, orient, legendAlign) {
    var type = sliderOptions.type,
        options = sliderOptions[type],
        isHorizontal = legendAlign.layout === 'horizontal';
    if (type === 'triangleUp' || type === 'triangleDown') {
        return [0, 0];
    } else if (type === 'lever' || type === 'vernier') {
        return [options.width, options.height];
    } else if (type === 'pentagon') {
        return [options.size + 2 * options.bandWidth, dimension[isHorizontal ? 1 : 0] + 1.5 * options.bandWidth + 2];
    } else {
        return [options.size, options.size];
    }
}

export { ZC_legend_minmaxLabels, getSliderSize };
